mapper.sql:
select b.mbom_id, b.mbom_code, b.mbom_name, b.product_id, p.product_code, p.product_name, b.version, b.effective_date, b.expire_date, b.status, b.create_by, b.create_time, b.update_by, b.update_time, b.remark
from mom_mbom b left join (
	select material_id product_id, material_code product_code, material_name product_name from mom_material where (material_type = 'product' or category_id in (select category_id from mom_material_category where category_code = 'FG' or category_name = '成品'))
) p on b.product_id = p.product_id

mapper.select:


	and b.mbom_code like concat('%', #{mbomCode}, '%')
	and b.mbom_name like concat('%', #{mbomName}, '%')
	and b.product_id = #{productId}
	and b.version like concat('%', #{version}, '%')
	and b.status = #{status}

order by b.mbom_id desc

mapper.update:
update mom_mbom
mbom_code = #{mbomCode}, mbom_name = #{mbomName}, product_id = #{productId}, version = #{version}, effective_date = #{effectiveDate}, expire_date = #{expireDate}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
where mbom_id = #{mbomId}

mapper.select:


	and i.mbom_id = #{mbomId}
	and i.parent_item_id = #{parentItemId}
	and i.material_id = #{materialId}
	and m.material_code like concat('%', #{materialCode}, '%')
	and m.material_name like concat('%', #{materialName}, '%')
	and i.status = #{status}

order by i.parent_item_id, i.item_seq, i.item_id

mapper.update:
update mom_mbom_item
parent_item_id = #{parentItemId}, material_id = #{materialId}, item_seq = #{itemSeq}, quantity = #{quantity}, scrap_rate = #{scrapRate}, operation_id = #{operationId}, step_id = #{stepId}, issue_type = #{issueType}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
where item_id = #{itemId}
